wsoc <- readr::read_csv("acc_wsoc.csv")

matrix <- readr::read_csv("matrix.csv")
```
:::


### GT Table


::: {.cell}

```{.r .cell-code}
wsoc_table <- wsoc |>
  dplyr::slice(1:14) |>
  dplyr::mutate(logo = team) |>
  dplyr::relocate(logo, .before = team) |>
  dplyr::mutate(diff = gf - ga) |>
  dplyr::arrange(-pts) |>
  dplyr::select(logo, team, pts, w, l, t, gf, ga, diff) |>
  gt::gt() |>
  gt::cols_label(
    # rename columns
    logo = "",
    team = "Team",
    pts = "Points",
    diff = "+/-",
    w = "W",
    l = "L",
    t = "T",
    gf = "+",
    ga = "-",
    diff = "+/-"
  ) |>
  gt::tab_spanner(label = "ACC Only",
                  columns = c(w, l, t)) |>
    gt::tab_spanner(label = "Goal Differential",
                  columns = c(gf, ga, diff)) |>
  cfbplotR::gt_fmt_cfb_logo(columns = "logo") |>
  gtExtras::gt_highlight_rows(
    rows = c(13:14),
    fill = "#FFEBEA",
    bold_target_only = TRUE
  ) |> 
  gtExtras::gt_highlight_rows(
    rows = c(1:5),
    fill = "#DDF0B2",
    bold_target_only = TRUE
  ) |> 
  gt::fmt(
    columns = c(diff),
    fns = function(x) {
      ifelse(x > 0, paste0("+", x), x)
    }
  ) |>
  gt::data_color(columns = c(w, l, t, gf, ga, diff),
                 colors = scales::col_numeric(
                   c(
                     "#0a4c6a",
                     "#73bfe2",
                     "#cfe8f3",
                     "#fff2cf",
                     "#fdd870",
                     "#fdbf11",
                     "#ca5800"
                   ),
                   domain = NULL
                 )) |>
  gt::tab_header(title = "ACC Women's Soccer: Conference Standings",
                 subtitle = "Teams in green have clinched a spot in ACC Tournament. Teams in red are eliminated, and the rest are competing for one spot.") |>
  gt::tab_source_note(source_note = "Bless your chart | October 20")  |>
  gtExtras::gt_theme_538() |>
  gt::tab_style(style = list(gt::cell_borders(
    sides = c("left"),
    color = "#c1c1c1",
    weight = gt::px(2)
  )),
  locations = list(gt::cells_body(columns = c(w, diff))))

gtExtras::gtsave_extra(wsoc_table,
                       filename = "wsoc_table.png",
                       vheight = 875,
                       vwidth = 600)

wsoc_table
```

