```{.r .cell-code}
tile_plot <- matrix |>  
              ggplot2::ggplot(ggplot2::aes(x = num, y = tie_number, fill = factor(unc_goal))) + 
  ggplot2::geom_tile(color = "white", size = .5) +
  ggplot2::scale_fill_manual(values = c("lightpink", "#56a0d3"), name = NULL) +
  ggplot2::coord_equal() +
  ggthemes::theme_fivethirtyeight() +
  ggplot2::theme(legend.position = "none", 
                 line = ggplot2::element_blank(),
                 axis.line = ggplot2::element_blank(),
                 axis.text = ggplot2::element_blank(),
                 panel.grid.major = ggplot2::element_blank(),
                 panel.grid.minor = ggplot2::element_blank()) + 
  ggplot2::labs(title = "North Carolina Women's Soccer is 9-0-7 overall \nTie games with goals shown below", 
                subtitle ="The Tar Heels have had a lead in all five of these games that have ended in a tie") + 
  ggplot2::annotate(
    cfbplotR::GeomCFBlogo,
    x = -.1,
    y = 1,
    team = "Alabama",
    height = .065,
